from flask import Flask, request, jsonify
import redis

app = Flask(__name__)
r = redis.StrictRedis(host='localhost', port=6379, db=0)

@app.route('/execute', methods=['GET'])
def execute_command():
    command = request.args.get('command')
    
    # Basic security check to prevent dangerous commands
    if command and not any(cmd in command.lower() for cmd in ['flushdb', 'flushall', 'config', 'shutdown']):
        try:
            result = r.execute_command(command)
            return jsonify({'result': result}), 200
        except Exception as e:
            return jsonify({'error': str(e)}), 400
    else:
        return jsonify({'error': 'Invalid command or command not allowed'}), 400

if __name__ == '__main__':
    app.run(debug=True)